mapper.select:
select count(1)
from DAC_ISSUE_DAY_STATISTICS

    1=1

        and CHECK_TIME >= to_date(#{startTime},'yyyy-mm-dd HH24:mi:ss')


        and CHECK_TIME <=  to_date(#{endTime},'yyyy-mm-dd HH24:mi:ss')


        and upper(DATA_NAME_ZH||'.'||DATA_NAME_EN) like #{searchContent}


        and UPDATE_RESULT = #{isExceptionJob}


        and UPDATE_RESULT = #{updateResult}


        and IS_PARTITION = #{isPartition}




                and (ACCEPT_CITY = #{acceptCity} or ACCEPT_CITY = #{local})


                AND ACCEPT_CITY = #{acceptCity}




        and TASK_STATE = #{taskState}


        and BASE_TIME_ENABLE = #{isBaseJob}

select CHECK_TIME, SOURCE_COUNT, PROVIDER_READ_COUNT, PROVIDER_WRITE_COUNT, ACCEPTOR_READ_COUNT, ACCEPTOR_WRITE_COUNT, DEST_COUNT, COURSE_CHAIN_RATIO,
HISTORICAL_COMPARISON, PROVIDER_START_TIME, PROVIDER_END_TIME, ACCEPTOR_START_TIME, ACCEPTOR_END_TIME, PROVIDER_DURATION, ACCEPTOR_DURATION, ALL_DURATION
, UPDATE_RESULT, UPDATE_RESULT_REASON, BASE_TIME
from DAC_ISSUE_DAY_STATISTICS
where JOB_ID = #{jobId}
and DATA_NAME_EN = #{dataNameEn}
and ACCEPT_CITY = #{acceptCity}
and CHECK_TIME >= to_date(#{endTime},'yyyy-mm-dd HH24:mi:ss')
and CHECK_TIME <=  to_date(#{checkTime},'yyyy-mm-dd HH24:mi:ss')

select * from ( select S.*, rownum rn from (select D.*, B.BASE_TIME, B.BASE_TIME_ENABLE from ( (SELECT JOB_ID, DATA_NAME_ZH, DATA_NAME_EN, ACCEPT_CITY, EXCHANGE_POSITION FROM DAC_ISSUE_DAY_STATISTICS
1=1
and upper(DATA_NAME_ZH||'.'||DATA_NAME_EN) like #{searchContent}
and IS_PARTITION = #{tableType}
and ACCEPT_CITY = #{acceptCity}
GROUP BY JOB_ID, DATA_NAME_ZH, DATA_NAME_EN, ACCEPT_CITY, EXCHANGE_POSITION) D left join DAC_ISSUE_BASE_TIME B on D.JOB_ID = B.JOB_ID and D.DATA_NAME_EN = B.DATA_NAME_EN )
order by
D.DATA_NAME_ZH ${sortType}, D.JOB_ID DESC
D.DATA_NAME_EN ${sortType}, D.JOB_ID DESC
B.BASE_TIME ${sortType}, D.JOB_ID DESC
) S where rownum <= #{pageSize}
and BASE_TIME_ENABLE = #{baseTimeEnable}
) where rn > #{pageNum}

select count(1) from ( (SELECT JOB_ID, DATA_NAME_ZH, DATA_NAME_EN, ACCEPT_CITY, EXCHANGE_POSITION FROM DAC_ISSUE_DAY_STATISTICS
1=1
and upper(DATA_NAME_ZH||'.'||DATA_NAME_EN) like #{searchContent}
GROUP BY JOB_ID, DATA_NAME_ZH, DATA_NAME_EN, ACCEPT_CITY, EXCHANGE_POSITION) D left join DAC_ISSUE_BASE_TIME B on D.JOB_ID = B.JOB_ID and D.DATA_NAME_EN = B.DATA_NAME_EN ) 1=1
and BASE_TIME_ENABLE = #{baseTimeEnable}
